import{_ as s,o as e,c as n,a5 as i}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"概念：单相逆变器故障状态机","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：单相逆变器故障状态机","tags":["power-electronics"],"status":"learning","summary":"状态机（state machine）把 UPS 软件运行过程拆成明确状态。本节只看一个很小的逆变器保护状态机："},"headers":[],"relativePath":"content/power/concepts/embedded/single-phase-inverter-fault-state-machine.md","filePath":"content/power/concepts/embedded/single-phase-inverter-fault-state-machine.md","lastUpdated":null}'),t={name:"content/power/concepts/embedded/single-phase-inverter-fault-state-machine.md"};function l(p,a,h,o,r,d){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="概念-单相逆变器故障状态机" tabindex="-1">概念：单相逆变器故障状态机 <a class="header-anchor" href="#概念-单相逆变器故障状态机" aria-label="Permalink to &quot;概念：单相逆变器故障状态机&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>状态机（state machine）把 UPS 软件运行过程拆成明确状态。本节只看一个很小的逆变器保护状态机：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>RUN -&gt; UV_LATCHED -&gt; RESET_WAIT -&gt; RUN</span></span></code></pre></div><p>故障锁存（fault latch）表示：一旦欠压保护（undervoltage protection / UV protection）确认故障，软件保存故障码、禁止脉宽调制（pulse-width modulation / PWM），并且不能因为 RMS 电压刚恢复就立刻重新输出。</p><p>本节中文主讲，只讲一个概念：不间断电源（uninterruptible power supply / UPS）保护判断和输出恢复必须经过状态机，而不是靠一个布尔变量直接开关 PWM。</p><p>本节不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据；学习记录中也不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>UPS 既要尽量持续供电，也要避免危险输出。上一节已经看到均方根（root mean square / RMS）欠压会触发故障锁存；本节关注故障之后软件怎么走。</p><p>如果欠压恢复后立刻开 PWM，系统可能反复启停，甚至在负载或功率级仍未稳定时重新输出。状态机让恢复条件变得清楚：故障已锁存、输出已关闭、电压已恢复、收到复位请求（reset request）、复位延时（reset delay）结束，然后才允许回到运行。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>状态机像电气柜的操作票。看到故障后先断开输出；故障信号消失只代表“当前测量值恢复”，不代表“可以马上合闸”。复位请求像操作员或上层逻辑说“可以尝试恢复”，复位延时像等待继电器、驱动、电容和软件计数器都稳定。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if state == RUN and V_rms &lt; UV_threshold for hold_time:</span></span>
<span class="line"><span>    fault = UNDERVOLTAGE</span></span>
<span class="line"><span>    state = UV_LATCHED</span></span>
<span class="line"><span>    pwm_enable = 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if state == UV_LATCHED and reset_request and V_rms &gt;= UV_threshold:</span></span>
<span class="line"><span>    state = RESET_WAIT</span></span>
<span class="line"><span>    reset_timer = 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>if state == RESET_WAIT:</span></span>
<span class="line"><span>    reset_timer += Ts</span></span>
<span class="line"><span>    if reset_timer &gt;= reset_delay:</span></span>
<span class="line"><span>        fault = NONE</span></span>
<span class="line"><span>        state = RUN</span></span>
<span class="line"><span>        pwm_enable = 1</span></span></code></pre></div><p>这里的重点是 <code>reset_request</code> 不能绕过电压恢复条件。</p><h2 id="_5-仿真观察" tabindex="-1">5. 仿真观察 <a class="header-anchor" href="#_5-仿真观察" aria-label="Permalink to &quot;5. 仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_inverter_fault_state_machine.py</span></span></code></pre></div><p>观察顺序：</p><ul><li><code>V_rms</code> 低于欠压阈值并保持足够时间后，状态从 <code>RUN</code> 进入 <code>UV_LATCHED</code>。</li><li><code>PWM enable</code> 在故障锁存期间变为 0。</li><li><code>Reset request</code> 出现后，如果 RMS 已恢复，状态进入 <code>RESET_WAIT</code>。</li><li><code>RESET_WAIT</code> 满足复位延时后，故障码清零并回到 <code>RUN</code>。</li></ul><p>脚本默认保存并自动打开图片；如果无法自动打开，会打印完整图片路径。</p><p>一个仿真任务：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_inverter_fault_state_machine.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">reset-request</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">time </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.11</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\inverter_fault_reset_early.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_inverter_fault_state_machine.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">reset-request</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">time </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.17</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\inverter_fault_reset_late.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>对比复位请求早于电压恢复和晚于电压恢复两种情况。重点看 <code>UV_LATCHED</code> 到 <code>RESET_WAIT</code> 的时刻，以及 <code>PWM enable</code> 什么时候重新变为 1。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>真实 C 工程常见分层：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Protection_Check()</span></span>
<span class="line"><span>  -&gt; updates fault request</span></span>
<span class="line"><span></span></span>
<span class="line"><span>FaultLatch_Update()</span></span>
<span class="line"><span>  -&gt; stores fault code</span></span>
<span class="line"><span></span></span>
<span class="line"><span>StateMachine_Step()</span></span>
<span class="line"><span>  -&gt; decides RUN / UV_LATCHED / RESET_WAIT</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pwm_ForceOff() or Pwm_Enable()</span></span>
<span class="line"><span>  -&gt; executes output gating</span></span></code></pre></div><p>读代码时要追三件事：故障码在哪里产生、在哪里锁存/清除、PWM 由哪个状态允许打开。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li>错误理解：保护条件恢复后就应该自动回 RUN。<br> 正确理解：严重故障通常要锁存，并经过复位流程。</li><li>错误理解：复位请求就是清故障码。<br> 正确理解：复位请求只是进入恢复流程的一个条件，还要看测量恢复和延时。</li><li>错误理解：PWM enable 只是显示状态。<br> 正确理解：PWM enable 是功率输出许可，必须由状态机和保护共同约束。</li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释 <code>RUN</code>、<code>UV_LATCHED</code>、<code>RESET_WAIT</code> 三个状态。</li><li>能在图中指出欠压触发、PWM 关断、复位请求、复位等待和恢复运行。</li><li>能解释为什么早到的复位请求不能绕过 RMS 恢复条件。</li><li>能说明故障码清零和 PWM 重新使能不是同一个瞬间随意发生的。</li><li>能基于仿真图准备导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>为什么 <code>V_rms</code> 恢复到阈值以上后，状态机仍可能停在 <code>UV_LATCHED</code>？</li><li>如果复位请求发生在 110 ms，而电压还没恢复，为什么不能立刻进入 <code>RUN</code>？</li><li>在真实 C 工程里，你会在哪些文件或函数名附近寻找 <code>PWM enable</code> 被强制关闭的逻辑？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>single_phase_inverter_fault_state_machine.py</code> 看到欠压触发后 PWM 立即变为 0。公司代码中输出欠压会直接关 PWM、切旁路，还是先降载/限流？</li><li>仿真里早于电压恢复的复位请求不会立刻回 RUN。真实工程里复位请求由按键、通信命令还是上层模式管理产生？</li><li>图中 <code>RESET_WAIT</code> 需要等待 20 ms。公司平台里恢复延时通常根据继电器、驱动芯片、母线电压还是软件滤波计数器决定？</li></ul>`,36)])])}const k=s(t,[["render",l]]);export{u as __pageData,k as default};
